/*
Custom config to pick the modules
 */
var reference = require('./module-reference.json');
var config = require('./module-config.json');

var getAvailableList = function(key) {
    return reference[key].available;
};
/*
To generate the list of entry files based on the given configuration
 */
var generateSourceFiles = function() {
    var source = [];

    //By default we need to add core and utilities
    source.push('core');

    //Available module names
    var moduleNames = ['components', 'chartTypes', 'themes', 'parsers', 'custom-visuals'];

    moduleNames.map(function(key) {
        var module = config[key],
            referenceModule = reference[key],
            available = referenceModule.available;

        // console.log(available);
        if (module) {
            if (key === 'themes') {
                source = source.concat(filterFiles(key, available, module.include, module.exclude));
            } else {
                var fixed = module.fixed,
                    custom = module.custom,
                    format = { prefix: module.path || referenceModule.path, suffix: module.suffix || referenceModule.suffix },
                    referenceCustom = referenceModule.custom;
                if (fixed) {
                    source = source.concat(filterFiles(key, available, fixed.include, fixed.exclude, null, format));
                }
                if (custom) {
                    var rootDirKeys = Object.keys(custom);
                    // console.log(rootDirKeys);
                    rootDirKeys.map(function(key1) {
                        var module1 = custom[key1],
                            available1 = referenceCustom[key1].available;
                        source = source.concat(filterFiles(key1, available1, module1.include, module1.exclude, true));
                    });
                }
            }
        }
    });
    source.push('end');
    var prefix = './js_list/',
        suffix = '.txt';
    source = source.map(d => prefix + d + suffix);
    // console.log("Generated file list:")
    // console.log(source)
    return source;
};

/*
Files filtering
available - List of available modules
includes - List of modules to include
excludes - List of modules to exclude
isCustomPick - need to select the particular file under the folder

For fixed type - includes and excludes list will be the main module folder names like axis, area ...
For custom type - includes and excludes list will be the child file names like canvasarea, polaraxis
        for this we need to add the core file by default.
 */
var filterFiles = function(root, available, includes, excludes, isCustomPick, format) {
    var source = isCustomPick ? [root + '/core'] : [],
        list;

    if (includes) {
        list = includes === '*' ? available : includes;
    } else if (excludes) {
        list =
            excludes === '*'
                ? []
                : available.filter(function(d, i) {
                      return excludes.indexOf(d) == -1;
                  });
    }
    source = source.concat(constructFileNames(list, root, isCustomPick, format));
    return source;
};

/*
construct the files names
list - contains list of module names
For custom pick , we need to append the list of modules under root directory
else we need to select the all the files under the given directory.

list - is directory name for fixed type, file names for custom type

root - is main module names for fixed and themes , directory name for custom type

 */
/**
 * 
 * @param {Array} list - array of files
 * @param {string} root - root folder of the files
 * @param {boolean} isCustomPick - picked file is custom or not to decide the file selector('' | '/*')
 * @param {object} format - custom format applied to file
 * @param {string} format.prefix - prefix applied to the array list of files
 * @param {string} format.suffix - suffix applied to the array list of files
 * @returns 
 */
var constructFileNames = function(list, root, isCustomPick, format = {}) {
    var fileSearch = isCustomPick || root == 'themes';
    var prefix = format.prefix ? format.prefix : fileSearch ? root + '/' : '',
        suffix = format.suffix ? format.suffix : fileSearch ? '' : '/*';
    var filesNames = list.map(function(d) {
        return prefix + d + suffix;
    });

    return filesNames;
};

exports.generateSourceFiles = generateSourceFiles;
